#include <stdio.h>
#include <stdlib.h>
int main(void) {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        unsigned int *a = (unsigned int*)malloc(N * sizeof(unsigned int));
        for (int i = 0; i < N; ++i) scanf("%u", &a[i]);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                if ((a[i] & a[j]) == a[i]) ++ans;
            }
        }
        printf("%lld\n", ans);
        free(a);
    }
    return 0;
}

